#include <stdio.h>
#include <stdlib.h>

typedef struct {int w; int l; int idx; long long pos;} Frog;
int cmp(const void *a, const void *b){return ((Frog*)a)->w - ((Frog*)b)->w;}

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        Frog *f = (Frog*)malloc(N*sizeof(Frog));
        for(int i=0;i<N;i++){scanf("%d", &f[i].w); f[i].idx=i; f[i].pos=i+1;}
        for(int i=0;i<N;i++){scanf("%d", &f[i].l);}        
        qsort(f, N, sizeof(Frog), cmp);
        long long ans=0; long long lastPos=0;
        for(int i=0;i<N;i++){
            while(f[i].pos<=lastPos){
                f[i].pos+=f[i].l;
                ans++;
            }
            lastPos=f[i].pos;
        }
        printf("%lld\n", ans);
        free(f);
    }
    return 0;
}

