const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = input[idx++];
let outputs = [];
for (let t = 0; t < T; t++) {
  const N = input[idx++];
  const W = new Array(N);
  const L = new Array(N);
  for (let i = 0; i < N; i++) W[i] = input[idx++];
  for (let i = 0; i < N; i++) L[i] = input[idx++];
  const order = [...Array(N).keys()].sort((a, b) => W[a] - W[b]);
  const pos = new Array(N);
  for (let i = 0; i < N; i++) pos[i] = i + 1;
  let ans = 0;
  let last = 0;
  for (const i of order) {
    while (pos[i] <= last) {
      pos[i] += L[i];
      ans++;
    }
    last = pos[i];
  }
  outputs.push(String(ans));
}
